if (! function_exists('maze_solver')) {
    function maze_solver($maze, $wall_char = null, $path_char = null, $solution_marker = null, $annotate = null)
    {
        $wall = $wall_char ?? '#';
        $open = $path_char ?? ' ';
        $dot = $solution_marker ?? '·';
        $stepNums = $annotate ?? false;

        // Parse maze into grid
        $lines = explode("\n", $maze);
        $grid = [];
        $start = null;
        $end = null;
        $height = count($lines);
        $width = 0;

        foreach ($lines as $r => $line) {
            $row = [];
            $len = strlen($line);
            if ($len > $width) $width = $len;
            for ($c = 0; $c < $len; $c++) {
                $ch = $line[$c];
                if ($ch === 'S') {
                    $start = [$r, $c];
                    $row[] = $open; // treat start as open
                } elseif ($ch === 'E') {
                    $end = [$r, $c];
                    $row[] = $open; // treat end as open
                } else {
                    $row[] = $ch;
                }
            }
            $grid[] = $row;
        }

        if (!$start) {
            return json_encode(['error' => 'No start (S) found in maze']);
        }
        if (!$end) {
            return json_encode(['error' => 'No end (E) found in maze']);
        }

        // BFS
        $directions = [[-1,0],[1,0],[0,-1],[0,1]]; // up, down, left, right
        $queue = [$start];
        $visited = [];
        $visited[$start[0] . ',' . $start[1]] = true;
        $parent = [];
        $found = false;

        while (!empty($queue)) {
            $current = array_shift($queue);
            $cr = $current[0];
            $cc = $current[1];
            
            if ($cr === $end[0] && $cc === $end[1]) {
                $found = true;
                break;
            }
            
            foreach ($directions as $d) {
                $nr = $cr + $d[0];
                $nc = $cc + $d[1];
                $key = $nr . ',' . $nc;
                
                if ($nr < 0 || $nr >= $height || $nc < 0 || $nc >= $width) continue;
                if (isset($visited[$key])) continue;
                
                $cell = $grid[$nr][$nc] ?? $wall;
                if ($cell === $wall) continue;
                
                $visited[$key] = true;
                $queue[] = [$nr, $nc];
                $parent[$key] = [$cr, $cc];
            }
        }

        if (!$found) {
            return json_encode([
                'error' => 'No path found from S to E',
                'start' => ['row' => $start[0], 'col' => $start[1]],
                'end' => ['row' => $end[0], 'col' => $end[1]],
                'cells_visited' => count($visited),
            ]);
        }

        // Reconstruct path from end to start
        $path = [];
        $current = $end;
        while ($current[0] !== $start[0] || $current[1] !== $start[1]) {
            $path[] = $current;
            $key = $current[0] . ',' . $current[1];
            $current = $parent[$key];
        }
        $path[] = $start;
        $path = array_reverse($path);

        $pathLen = count($path) - 1; // steps (edges), not nodes

        // Build solution grid
        $solutionGrid = [];
        foreach ($grid as $r => $row) {
            $solutionGrid[$r] = [];
            foreach ($row as $c => $ch) {
                if ($r === $start[0] && $c === $start[1]) {
                    $solutionGrid[$r][$c] = 'S';
                } elseif ($r === $end[0] && $c === $end[1]) {
                    $solutionGrid[$r][$c] = 'E';
                } else {
                    $solutionGrid[$r][$c] = $ch;
                }
            }
        }

        // Mark the path
        $pathCoords = [];
        foreach ($path as $i => $p) {
            $r = $p[0];
            $c = $p[1];
            if ($r === $start[0] && $c === $start[1]) continue;
            if ($r === $end[0] && $c === $end[1]) continue;
            if ($stepNums) {
                $solutionGrid[$r][$c] = (string)($i % 10);
            } else {
                $solutionGrid[$r][$c] = $dot;
            }
            $pathCoords[] = ['row' => $r, 'col' => $c, 'step' => $i];
        }

        // Render solution as string
        $solutionLines = [];
        foreach ($solutionGrid as $row) {
            $solutionLines[] = implode('', $row);
        }
        $solutionStr = implode("\n", $solutionLines);

        return json_encode([
            'solved' => true,
            'path_length_steps' => $pathLen,
            'path_nodes' => count($path),
            'start' => ['row' => $start[0], 'col' => $start[1]],
            'end' => ['row' => $end[0], 'col' => $end[1]],
            'path' => array_map(function($p) {
                return ['row' => $p[0], 'col' => $p[1]];
            }, $path),
            'path_coords' => $pathCoords,
            'solution_grid' => $solutionStr,
            'cells_visited' => count($visited),
            'exploration_efficiency' => round(count($path) / max(count($visited), 1) * 100, 1) . '%',
            'next_steps' => [
                "Feed 'path' coordinates into text_coordinate_grid for emoji rendering.",
                "Feed 'solution_grid' to write_file to save the solved maze."
            ],
        ]);
    }
